module counter2bit(
    input clk,
    input reset,
    input enable,

    output reg [1:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        count <= 0;
    else if (enable)
        count <= count + 1;
end

endmodule
